//! HTTP async operation fee calculations (executor-specific)
//!
//! HTTP executor fees are operation-specific because they cover the actual
//! cost of making HTTP requests (bandwidth, processing, etc.)

use crate::constants::*;

destinations.snippet:
pub fn http_executor_fee(input_len: usize, output_len: usize) -> U256 {
    let input_component =
        U256::from(HTTP_EXECUTOR_FEE_PER_INPUT_BYTE_WEI) * U256::from(input_len as u64);
    let output_component =
        U256::from(HTTP_EXECUTOR_FEE_PER_OUTPUT_BYTE_WEI) * U256::from(output_len as u64);

